224: const State = struct {
225:     // The effective buffer to process Vietnamese input. we will skip processing if the buffer
226:     // longer than 16.
227:     buffer_effective: [16]Span,
228:     // The maximum buffer length that the engine still keeps the effective buffer, after the maximum
229:     // value (255), we will reset the effective buffer and this value.
230:     buffer_length: u8 = 0,
231:     // Mark the earliest position (inclusive) in buffer where we modified the span, will be used to
232:     // calculate backspaces and replacement characters.
233:     buffer_modification_index: ?u8 = null,
234:     // Mark the position (inclusive) in buffer where we will switch to literal mode (due to manually
235:     // switch, input cancellation, exceed effective buffer). This value is only used in .telex mode
236:     // and the engine is working on position on or after literal index, the engine will skip
237:     // Vietnamese input processing (we only count valid numbers, null mean no literal index).
238:     literal_index: ?u8 = null,
239:     // Determine if we will process input in the specified mode (Telex) or append the character as is.
240:     mode: InputMode = .literal,
241: 
242:     // Initialize the State on allocated memory.
243:     fn init(self: *State) void {
244:         self.* = .{
245:             .buffer_effective = undefined,
246:         };
247:     }
248: 
249:     fn add(self: *State, c: u8) void {
250:         // Only allow a-zA-Z.
251:         assert(std.ascii.isAlphabetic(c));
252: 
253:         // The buffer_modification index must be inbound of the buffer_effective.
254:         assert(self.buffer_modification_index == null or (self.buffer_modification_index.? < self.buffer_effective.len and self.buffer_modification_index.? < self.buffer_length));
255: 
256:         // Input mode must be either .literal or .telex.
257:         assert(self.mode == .literal or self.mode == .telex);
258: 
259:         // Should never set literal_index in .literal mode.
260:         if (self.mode == .literal) {
261:             assert(self.literal_index == null);
262:         }
263: 
264:         if (self.literal_index) |literal_index| {
265:             // When literal_index is set, mode must be .telex.
266:             assert(self.mode == .telex);
267:             // The literal_index value must be in range null or 0 -> 16 (buffer_effective length)
268:             // because we won't process Vietnamese input outside the buffer_effective.
269:             assert(literal_index <= self.buffer_effective.len);
270:             // The literal_index value must be less than buffer length.
271:             assert(literal_index < self.buffer_length);
272:         }
273: 
274:         // buffer_length conditions
275:         // 1. must be within buffer_effective length in Vietnamese input.
276:         // 2. could be more than buffer_effective in literal input.
277:         assert(self.buffer_length <= self.buffer_effective.len or self.mode == .literal or self.literal_index != null);
278: 
279:         switch (c) {
280:             'A', 'a' => {
281:                 if (self.literal_index != null or self.mode == .literal or self.buffer_length == 0) {
282:                     // 1. Enable literal input when literal_index is set or on literal mode. The
283:                     // literal_index is also set when the word starts with non-Vietnamese onsets.
284:                     // 2. Append literal because no previous span existed. Continue Vietnamese
285:                     // processing on next input.
286:                     self.append_literal(c);
287:                     // Set modification index to null because we didn't modify any existing span.
288:                     self.buffer_modification_index = null;
289:                 } else if (self.buffer_effective_last().equals_ignore_case_and_tone(c, .empty)) {
290:                     // 3. Previous span is 'A' or 'a', apply circumflex.
291:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
292:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
293:                     // Set modification index for calculating synthetic backspace.
294:                     self.buffer_modification_index = self.buffer_length - 1;
295:                 } else if (self.buffer_effective_last().equals_ignore_case_and_tone(c, .breve)) {
296:                     // 4. Previous span is 'Ă' or 'ă', override to circumflex.
297:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
298:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
299:                     // Set modification index for calculating synthetic backspace.
300:                     self.buffer_modification_index = self.buffer_length - 1;
301:                 } else if (self.buffer_effective_last().equals_ignore_case_and_tone(c, .circumflex)) {
302:                     // 5. Previous span is 'Â' or 'â', cancel circumflex for previous span and append new literal span.
303:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
304:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .empty, span_previous.tone);
305:                     // Set modification index for calculating synthetic backspace.
306:                     self.buffer_modification_index = self.buffer_length - 1;
307:                     // Start literal input from this position.
308:                     self.literal_index = self.buffer_length;
309:                     // Append literal 'A' or 'a'.
310:                     self.append_literal(c);
311:                 } else if (!self.buffer_effective_last().equals_base(c)) {
312:                     // 6. Append literal when previous span is not 'A', 'a' and its variants.
313:                     self.append_literal(c);
314:                     // No modification.
315:                     self.buffer_modification_index = null;
316:                 } else {
317:                     unreachable;
318:                 }
319:             },
320:             'C', 'c' => { // fill missing diacritic, e.g. cước.
321:                 if (self.literal_index != null or self.mode == .literal or self.buffer_length < 2) {
322:                     // 1. Enable literal input when literal_index is set or on literal mode. The
323:                     // literal_index is also set when the word starts with non-Vietnamese onsets.
324:                     // 2. Append literal because no previous span existed. Continue Vietnamese
325:                     // processing on next input.
326:                     // 3. Buffer is less than 2 characters to start with.
327:                     self.append_literal(c);
328:                     // Set modification index to null because we didn't modify any existing span.
