1427:         self.buffer_length -= 1;
1428:         // because backspace doesn't retro-modify the buffer, unset the buffer_modification_index.
1429:         self.buffer_modification_index = null;
1430:         // if the literal_index is out of buffer range, unset it.
1431:         if (self.literal_index != null and self.literal_index.? == self.buffer_length) {
1432:             self.literal_index = null;
